// src/components/MoldList.js

import React, {useState, useEffect, useCallback} from 'react';
import {supabase} from '../supabaseClient';
import {useNavigate, Link} from 'react-router-dom';
import {
    Paper,
    Button,
    CircularProgress,
    Alert,
    Typography,
    TextField,
    useMediaQuery,
    useTheme,
    Select,
    MenuItem,
    TableContainer,
    Table,
    TableHead,
    TableRow,
    TableCell,
    TableBody,
} from '@mui/material';
import {styled} from '@mui/material/styles';

const StyledTableCell = styled(TableCell)(({theme}) => {
    const isSmallScreen = theme.breakpoints.down('sm');
    return {
        [`&.owner-id`]: {
            display: 'table-cell',
            [isSmallScreen]: {
                display: 'none',
            },
        },
    };
});

const StyledTableRow = styled(TableRow)(() => ({}));

// 간단한 영어-한글 매핑 (더 많은 단어 필요)
const engToKorMap = {
    'Mold List': '몰드 목록',
    'New Mold': '새 몰드',
    'Mold ID': '몰드 ID',
    'Status': '상태',
    'Status Date/Time': '상태 날짜/시간',
    'Inspection Status': '검사 상태',
    'Inspector': '검사자',
    'Mold Count': '몰드 카운트',
    'Save': '저장',
    'Cancel': '취소',
    'Search Molds': '몰드 조회',
    'ID': 'ID',
    'Delete': '삭제',
    'Edit': '수정',
    'Logout': '로그아웃',
    'Add New Mold': '새 몰드 추가',
    'Received': '접수됨',
    'Shipped': '배송됨',
    'WAITING': '대기',
    'PASS': '합격',
    'FAIL': '불합격',
    'Owner ID': '소유자 ID',
};

function MoldList() {
    const [molds, setMolds] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const navigate = useNavigate();
    const [newMoldId, setNewMoldId] = useState('');
    const [newStatus, setNewStatus] = useState('');
    const [newStatusDate, setNewStatusDate] = useState('');
    const [newInspectionStatus, setNewInspectionStatus] = useState('');
    const [newInspector, setNewInspector] = useState('');
    // const [newOwnerId, setNewOwnerId] = useState('');
    const [newMoldCount, setNewMoldCount] = useState('');
    const [isAddingNew, setIsAddingNew] = useState(false);
    const [currentLanguage, setCurrentLanguage] = useState('ko'); // 'ko' 또는 'en'

    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down('sm'));

    const fetchMolds = useCallback(async () => {
        try {
            const {data, error} = await supabase.from('molds').select('*');
            if (error) throw error;
            setMolds(data);
        } catch (err) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    }, [supabase]);

    useEffect(() => {
        fetchMolds();
    }, [fetchMolds]);

    const handleLogout = async () => {
        await supabase.auth.signOut();
        navigate('/');
    };

    const handleDelete = async (id) => {
        try {
            const {error} = await supabase.from('molds').delete().eq('id', id);
            if (error) throw error;
            setMolds(molds.filter((mold) => mold.id !== id));
        } catch (err) {
            setError(err.message);
        }
    };

    const handleAddNewClick = () => {
        setIsAddingNew(true);
    };

    const handleCancelAdd = () => {
        setIsAddingNew(false);
        setNewMoldId('');
        setNewStatus('');
        setNewStatusDate('');
        setNewInspectionStatus('');
        setNewInspector('');
        // setNewOwnerId('');
        setNewMoldCount('');
    };

    const handleSaveNewMold = async () => {
        if (!newMoldId) {
            alert(currentLanguage === 'ko' ? '몰드 ID를 입력해주세요.' : 'Please enter Mold ID.');
            return;
        }
        try {
            // 현재 사용자 세션 정보 가져오기
            const {data: session, error: sessionError} = await supabase.auth.getSession();

            // 세션 정보가 없거나 사용자 ID가 없는 경우 에러 처리
            if (sessionError || !session?.session?.user?.id) {
                alert(currentLanguage === 'ko' ? '로그인 후 이용해주세요.' : 'Please log in to continue.');
                return;
            }

            // 현재 로그인한 사용자의 UUID
            const currentUserId = session.session.user.id;

            const {error} = await supabase.from('molds').insert([
                {
                    mold_id: newMoldId,
                    status: newStatus,
                    status_date: newStatusDate,
                    inspection_status: newInspectionStatus,
                    inspector: newInspector,
                    owner_id: currentUserId, // 현재 사용자 ID를 owner_id에 할당
                    mold_count: parseInt(newMoldCount, 10) || 0,
                },
            ]);
            if (error) throw error;
            handleCancelAdd();
            fetchMolds();
            alert(currentLanguage === 'ko' ? '새 몰드가 추가되었습니다.' : 'New mold added successfully.');
        } catch (err) {
            setError(err.message);
        }
    };

    // 조회 화면으로 이동하는 함수
    const handleSearchClick = () => {
        navigate('/mold-search'); // MoldSearch.js로 이동
    };
    const toggleLanguage = () => {
        setCurrentLanguage(prevLang => (prevLang === 'ko' ? 'en' : 'ko'));
    };
    const translate = (key) => {
        return engToKorMap[key] || key;
    };

    if (loading) return <CircularProgress/>;
    if (error) return <Alert severity="error">{error}</Alert>;

    return (
        <div>
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px'}}>
                <Typography variant="h5">{translate('Mold List')}</Typography>
                <Button variant="outlined" onClick={toggleLanguage}>
                    {currentLanguage === 'ko' ? 'English' : '한국어'}
                </Button>
            </div>
            <Button variant="contained" color="primary" onClick={handleAddNewClick} style={{marginBottom: '10px'}}>
                {translate('Add New Mold')}
            </Button>
            <Button variant="contained" color="primary" onClick={handleSearchClick} style={{marginBottom: '10px'}}>
                {translate('Search Molds')}
            </Button>
            {isAddingNew && (
                <Paper style={{padding: '15px', marginBottom: '10px'}}>
                    <Typography variant="h6">{translate('New Mold')}</Typography>
                    <TextField
                        label={translate('Mold ID')}
                        value={newMoldId}
                        onChange={(e) => setNewMoldId(e.target.value)}
                        fullWidth
                        margin="normal"
                    />
                    <Select
                        label={translate('Status')}
                        value={newStatus}
                        onChange={(e) => setNewStatus(e.target.value)}
                        fullWidth
                        margin="normal"
                    >
                        <MenuItem value="Received">Received</MenuItem>
                        <MenuItem value="Shipped">Shipped</MenuItem>
                        {/* 필요한 상태 옵션 추가 */}
                    </Select>
                    <TextField
                        label={translate('Status Date/Time')}
                        type="datetime-local"
                        value={newStatusDate}
                        onChange={(e) => setNewStatusDate(e.target.value)}
                        fullWidth
                        margin="normal"
                    />
                    <Select
                        label={translate('Inspection Status')}
                        value={newInspectionStatus}
                        onChange={(e) => setNewInspectionStatus(e.target.value)}
                        fullWidth
                        margin="normal"
                    >
                        <MenuItem value="WAITING">WAITING</MenuItem>
                        <MenuItem value="PASS">PASS</MenuItem>
                        <MenuItem value="FAIL">FAIL</MenuItem>
                        {/* 필요한 검사 상태 옵션 추가 */}
                    </Select>
                    <TextField
                        label={translate('Inspector')}
                        value={newInspector}
                        onChange={(e) => setNewInspector(e.target.value)}
                        fullWidth
                        margin="normal"
                    />
                    {/*}
          <TextField
            label="소유자 ID"
            value={newOwnerId}
            onChange={(e) => setNewOwnerId(e.target.value)}
            fullWidth
            margin="normal"
          />
          */}
                    <TextField
                        label={translate('Mold Count')}
                        type="number"
                        value={newMoldCount}
                        onChange={(e) => setNewMoldCount(e.target.value)}
                        fullWidth
                        margin="normal"
                    />
                    <Button variant="contained" color="primary" onClick={handleSaveNewMold}
                            style={{marginRight: '10px'}}>
                        {translate('Save')}
                    </Button>
                    <Button variant="outlined" onClick={handleCancelAdd}>
                        {translate('Cancel')}
                    </Button>
                </Paper>
            )}

            {isMobile ? (
                molds.map((mold) => (
                    <Paper key={mold.id} style={{margin: '10px', padding: '15px'}}>
                        <Typography variant="subtitle1">mold ID: {mold.mold_id}</Typography>
                        <Typography variant="body2">Status: {mold.status}</Typography>
                        <Typography variant="body2">Status date: {mold.status_date}</Typography>
                        <Typography variant="body2">Inspection status: {mold.inspection_status}</Typography>
                        <Typography variant="body2">Inspector: {mold.inspector}</Typography>
                        <Typography variant="body2" className="owner-id">소유자 ID: {mold.owner_id}</Typography>
                        <Typography variant="body2">Mold Count: {mold.mold_count}</Typography>
                        <Button size="small" color="secondary" onClick={() => handleDelete(mold.id)}
                                style={{marginRight: '5px'}}>
                            삭제
                        </Button>
                        <Link to={`/mold-edit/${mold.id}`} style={{textDecoration: 'none'}}>
                            <Button size="small" color="primary">수정</Button>
                        </Link>
                    </Paper>
                ))
            ) : (
                <TableContainer component={Paper} style={{marginTop: '20px', overflowX: 'auto'}}>
                    <Table>
                        <TableHead>
                            <TableRow>
                                <TableCell>{translate('ID')}</TableCell>
                                <TableCell>{translate('Mold ID')}</TableCell>
                                <TableCell>{translate('Status')}</TableCell>
                                <TableCell>{translate('Status Date')}</TableCell>
                                <TableCell>{translate('Inspection Status')}</TableCell>
                                <TableCell>{translate('Inspector')}</TableCell>
                                <StyledTableCell className="owner-id">소유자 ID</StyledTableCell>
                                <TableCell>{translate('Mold Count')}</TableCell>
                                <TableCell>{translate('Delete')}</TableCell>
                                <TableCell>{translate('Edit')}</TableCell>
                            </TableRow>
                        </TableHead>
                        <TableBody>
                            {molds.map((mold) => (
                                <StyledTableRow key={mold.id}>
                                    <TableCell>{mold.id}</TableCell>
                                    <TableCell>{mold.mold_id}</TableCell>
                                    <TableCell>{mold.status}</TableCell>
                                    <TableCell>{mold.status_date}</TableCell>
                                    <TableCell>{mold.inspection_status}</TableCell>
                                    <TableCell>{mold.inspector}</TableCell>
                                    <StyledTableCell className="owner-id">{mold.owner_id}</StyledTableCell>
                                    <TableCell>{mold.mold_count}</TableCell>
                                    <TableCell>
                                        <Button variant="outlined" color="secondary"
                                                onClick={() => handleDelete(mold.id)} size="small">
                                            {translate('Delete')}
                                        </Button>
                                    </TableCell>
                                    <TableCell>
                                        <Link to={`/mold-edit/${mold.id}`} style={{textDecoration: 'none'}}>
                                            <Button variant="outlined" color="primary" size="small">
                                                {translate('Edit')}
                                            </Button>
                                        </Link>
                                    </TableCell>
                                </StyledTableRow>
                            ))}
                        </TableBody>
                    </Table>
                </TableContainer>
            )}

            <Button variant="contained" color="primary" onClick={handleLogout} style={{marginTop: '20px'}}>
                {translate('Logout')}
            </Button>
        </div>
    );
}

export default MoldList;
